arguments.new_str:
using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains and evaluates the ticket classification model at startup,
/// then saves the model to disk for PredictionEnginePool consumption.
/// </summary>
public sealed class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly LabelMap _labelMap;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env, LabelMap labelMap)
    {
        _logger = logger;
        _labelMap = labelMap;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        _logger.LogInformation("Training ticket classification model...");

        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority into a single Features vector
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        ITransformer model = pipeline.Fit(split.TrainSet);

        // Extract label names from the Score column's slot metadata
        ExtractLabelNames(model, split.TrainSet);

        // Evaluate on held-out test set
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation(
            "Model evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        LogPerClassMetrics(metrics);

        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;

    private void ExtractLabelNames(ITransformer model, IDataView trainData)
    {
        var transformedSchema = model.GetOutputSchema(trainData.Schema);
        var scoreColumn = transformedSchema["Score"];

        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);

        _labelMap.Labels = slotNames.DenseValues()
            .Select(v => v.ToString())
            .ToArray();

        _logger.LogInformation("Label order: {Labels}", string.Join(", ", _labelMap.Labels));
    }

    private void LogPerClassMetrics(Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        var confusionMatrix = metrics.ConfusionMatrix;
        var precision = confusionMatrix.PerClassPrecision;
        var recall = confusionMatrix.PerClassRecall;

        for (int i = 0; i < precision.Count; i++)
        {
            string label = i < _labelMap.Labels.Length ? _labelMap.Labels[i] : $"Class {i}";
            _logger.LogInformation(
                "  {Label}: Precision={Precision:F4}, Recall={Recall:F4}",
                label, precision[i], recall[i]);
        }

        _logger.LogInformation("Confusion matrix:\n{Matrix}",
            confusionMatrix.GetFormattedConfusionTable());
    }
}

